clear;
clc;
nu = 0.3;
N = 100;
h = 1/N;
r = linspace(0,1,N+1)';
A = zeros(N+1,N+1);
b = zeros(N+1,1);
A(1,1) = 1;
b(1) = 0;
for j = 2:N
    rj = r(j);
    a = 1/h^2 - 1/(2*h*rj);
    c = -2/h^2 - 1/rj^2;
    d = 1/h^2 + 1/(2*h*rj);
    A(j,j-1) = a;
    A(j,j)   = c;
    A(j,j+1) = d;
end
A(N+1,N)   = -(1-nu)/h;
A(N+1,N+1) = (1-nu)/h + nu;
b(N+1) = -(1+nu)*(1-2*nu);
u_num = A\b;
u_exact = -(1+nu)*(1-2*nu)*r;
max_error = max(abs(u_num-u_exact));
fprintf('Maximum error = %e\n',max_error); %[output:98eb222e]
figure; %[output:0f276f8d]
plot(r,u_num,'LineWidth',2); %[output:0f276f8d]
hold on; %[output:0f276f8d]
plot(r,u_exact,'--','LineWidth',2); %[output:0f276f8d]
xlabel('Dimensionless Radius, r'); %[output:0f276f8d]
ylabel('Dimensionless Displacement, u'); %[output:0f276f8d]
legend('FDM Solution','Analytical Solution'); %[output:0f276f8d]
grid on; %[output:0f276f8d]
